"""Export a PyTorch LoRA adapter to GGUF format for llama.cpp inference.

Closes the train→deploy loop on iPad: train a LoRA via PyTorch (using
the Metal GPU bridge for speed), then convert the resulting `.pt`
adapter to a GGUF file that llama.cpp can load via the `/lora` command
for fast Metal-accelerated inference of the merged model.

Usage from Python:

    from _cb_gguf_export import export_lora_to_gguf
    export_lora_to_gguf(
        pt_path="~/Documents/qwen-lora.pt",
        gguf_path="~/Documents/qwen-lora.gguf",
        base_arch="qwen2",   # one of: llama, qwen2, mistral, phi, etc.
        alpha=16.0,
    )

Or from the shell:

    python -m _cb_gguf_export --pt qwen-lora.pt --gguf qwen-lora.gguf \\
                              --arch qwen2 --alpha 16

Supported source key formats (auto-detected):
  - HF PEFT: `base_model.model.layers.<n>.<module>.lora_{A,B}.weight`
  - Hand-rolled: `model.layers.<n>.<module>.lora_{A,B}.weight`
  - Stripped: `layers.<n>.<module>.lora_{A,B}.weight`

Where `<module>` is one of:
  self_attn.q_proj / k_proj / v_proj / o_proj
  mlp.gate_proj / up_proj / down_proj

These cover Qwen / Llama / Mistral / Phi-family architectures. For
other model families the user has to extend `_MODULE_MAP`.

GGUF spec ref: https://github.com/ggerganov/ggml/blob/master/docs/gguf.md
"""
from __future__ import annotations
import argparse
import os
import struct
import sys
from typing import Optional

# ─── GGUF constants ───────────────────────────────────────────────
GGUF_MAGIC   = 0x46554747   # "GGUF" little-endian
GGUF_VERSION = 3

# GGUF metadata value types
_GT_UINT8   = 0
_GT_INT8    = 1
_GT_UINT16  = 2
_GT_INT16   = 3
_GT_UINT32  = 4
_GT_INT32   = 5
_GT_FLOAT32 = 6
_GT_BOOL    = 7
_GT_STRING  = 8
_GT_ARRAY   = 9
_GT_UINT64  = 10
_GT_INT64   = 11
_GT_FLOAT64 = 12

# GGUF tensor data types (GGML enum)
_TT_F32   = 0
_TT_F16   = 1
_TT_BF16  = 30

# Data section alignment (GGUF default — read from general.alignment if present)
_ALIGNMENT = 32

# ─── PyTorch LoRA → GGUF tensor name mapping ──────────────────────
# Module path in HF PEFT format → GGUF tensor stem.
# Right side matches what llama.cpp expects in adapter GGUF files.
_MODULE_MAP = {
    "self_attn.q_proj":  "attn_q",
    "self_attn.k_proj":  "attn_k",
    "self_attn.v_proj":  "attn_v",
    "self_attn.o_proj":  "attn_output",
    "mlp.gate_proj":     "ffn_gate",
    "mlp.up_proj":       "ffn_up",
    "mlp.down_proj":     "ffn_down",
}


def _ws(f, s: str):
    """Write a length-prefixed UTF-8 string (u64 length + bytes)."""
    b = s.encode("utf-8")
    f.write(struct.pack("<Q", len(b)))
    f.write(b)


def _wkv(f, key: str, value):
    """Write a metadata key-value pair."""
    _ws(f, key)
    if isinstance(value, bool):
        f.write(struct.pack("<I", _GT_BOOL))
        f.write(struct.pack("<?", value))
    elif isinstance(value, int):
        f.write(struct.pack("<I", _GT_UINT32))
        f.write(struct.pack("<I", value))
    elif isinstance(value, float):
        f.write(struct.pack("<I", _GT_FLOAT32))
        f.write(struct.pack("<f", value))
    elif isinstance(value, str):
        f.write(struct.pack("<I", _GT_STRING))
        _ws(f, value)
    else:
        raise TypeError(f"unsupported metadata value type: {type(value)}")


def _tensor_dtype_code(torch_dtype):
    import torch
    if torch_dtype == torch.float32: return _TT_F32, 4
    if torch_dtype == torch.float16: return _TT_F16, 2
    if torch_dtype == torch.bfloat16: return _TT_BF16, 2
    raise TypeError(f"unsupported tensor dtype: {torch_dtype}")


def _strip_prefix(key: str) -> str:
    """Strip the standard HF PEFT / hand-rolled prefixes so we land on
    `layers.<n>.<module>.lora_X.weight`."""
    for prefix in ("base_model.model.", "base_model.", "model."):
        if key.startswith(prefix):
            return key[len(prefix):]
    return key


def _map_lora_key(pt_key: str) -> Optional[str]:
    """Convert a PyTorch LoRA state-dict key to a GGUF tensor name.

    PyTorch (HF PEFT):
        base_model.model.layers.5.self_attn.q_proj.lora_A.weight
    GGUF:
        blk.5.attn_q.weight.lora_a

    Returns None for keys we don't recognise (caller skips them)."""
    key = _strip_prefix(pt_key)
    if not key.startswith("layers."):
        return None
    parts = key.split(".")
    if len(parts) < 5 or parts[-1] != "weight":
        return None
    lora_part = parts[-2].lower()
    if lora_part not in ("lora_a", "lora_b"):
        return None
    try:
        layer = int(parts[1])
    except ValueError:
        return None
    module = ".".join(parts[2:-2])
    gguf_module = _MODULE_MAP.get(module)
    if gguf_module is None:
        return None
    return f"blk.{layer}.{gguf_module}.weight.{lora_part}"


def _tensor_bytes(t):
    """Return the raw bytes of a CPU tensor in its native dtype.
    Works for fp32 / fp16 / bf16 — for bf16 we view as int16 to get a
    buffer-protocol-compatible storage (torch's buffer protocol on
    bf16 is iffy across versions)."""
    import torch
    t = t.contiguous()
    if t.dtype == torch.bfloat16:
        return bytes(t.view(torch.int16).untyped_storage()
                     )[:t.numel() * 2]
    n_bytes = t.numel() * t.element_size()
    return bytes(t.untyped_storage())[:n_bytes]


def export_lora_to_gguf(pt_path: str, gguf_path: str,
                       base_arch: str = "qwen2",
                       alpha: float = 16.0,
                       force_dtype: Optional[str] = None) -> dict:
    """Convert a PyTorch LoRA adapter to GGUF.

    Args:
        pt_path:     path to the .pt file (either a raw state_dict or
                     a checkpoint dict with `model_state_dict` key).
        gguf_path:   output GGUF path.
        base_arch:   base model architecture name (llama / qwen2 /
                     mistral / phi / etc.). llama.cpp uses this to
                     route tensor names to its internal layout.
        alpha:       LoRA alpha (scaling) the adapter was trained with.
        force_dtype: optional cast for all tensors — one of "f32",
                     "f16", "bf16". Default: keep input dtype.

    Returns a stats dict for logging.
    """
    import torch

    pt_path = os.path.expanduser(pt_path)
    gguf_path = os.path.expanduser(gguf_path)

    state = torch.load(pt_path, map_location="cpu")
    if isinstance(state, dict) and "model_state_dict" in state:
        state = state["model_state_dict"]
    if not isinstance(state, dict):
        raise ValueError(f"checkpoint at {pt_path} isn't a state_dict")

    # Map keys → GGUF names; skip non-LoRA tensors
    dtype_cast = {"f32": torch.float32, "f16": torch.float16,
                  "bf16": torch.bfloat16}.get(force_dtype) if force_dtype else None
    tensors = []           # list of (gguf_name, tensor)
    skipped = []
    for k, v in state.items():
        if not isinstance(v, torch.Tensor):
            continue
        name = _map_lora_key(k)
        if name is None:
            skipped.append(k)
            continue
        if dtype_cast is not None:
            v = v.to(dtype_cast)
        tensors.append((name, v.contiguous().cpu()))

    if not tensors:
        first_keys = list(state.keys())[:5]
        raise ValueError(
            f"no LoRA tensors found at {pt_path}. First keys seen:\n"
            + "\n".join(f"  {k}" for k in first_keys) +
            "\nIf your adapter uses different naming, extend _MODULE_MAP.")

    # Metadata kvs (order doesn't matter functionally, but llama.cpp
    # likes to read general.* first).
    kvs = [
        ("general.architecture", base_arch),
        ("general.type",         "adapter"),
        ("general.alignment",    _ALIGNMENT),
        ("adapter.type",         "lora"),
        ("adapter.lora.alpha",   float(alpha)),
    ]

    # ─── Write file ────────────────────────────────────────────
    with open(gguf_path, "wb") as f:
        # Header
        f.write(struct.pack("<I", GGUF_MAGIC))
        f.write(struct.pack("<I", GGUF_VERSION))
        f.write(struct.pack("<Q", len(tensors)))
        f.write(struct.pack("<Q", len(kvs)))

        # Metadata
        for k, v in kvs:
            _wkv(f, k, v)

        # Tensor metadata: name + n_dims + dims[] + dtype + offset
        # Offsets are relative to the start of the tensor-data section,
        # which is the file position AFTER all tensor metadata + alignment.
        # So compute size of all tensor metadata first.
        meta_size = 0
        for name, t in tensors:
            meta_size += 8 + len(name.encode("utf-8"))   # length-prefixed string
            meta_size += 4                                # n_dims (u32)
            meta_size += 8 * t.dim()                      # dims (u64 each)
            meta_size += 4                                # dtype (u32)
            meta_size += 8                                # offset (u64)

        # Where tensor data will start (after metadata + alignment padding).
        data_section_start = f.tell() + meta_size
        padding = (_ALIGNMENT - data_section_start % _ALIGNMENT) % _ALIGNMENT

        # Per-tensor offsets relative to data_section_start. Each tensor
        # is followed by padding so the next one is aligned.
        offsets = []
        cursor = 0
        for name, t in tensors:
            offsets.append(cursor)
            _, elem_size = _tensor_dtype_code(t.dtype)
            n_bytes = t.numel() * elem_size
            n_bytes_aligned = (n_bytes + _ALIGNMENT - 1) & ~(_ALIGNMENT - 1)
            cursor += n_bytes_aligned

        # Write tensor metadata.
        for (name, t), off in zip(tensors, offsets):
            _ws(f, name)
            f.write(struct.pack("<I", t.dim()))
            # GGUF stores dims in reverse order (matches GGML's row-major
            # column-first layout — last torch dim becomes first GGUF dim).
            for d in reversed(t.shape):
                f.write(struct.pack("<Q", int(d)))
            dtype_code, _ = _tensor_dtype_code(t.dtype)
            f.write(struct.pack("<I", dtype_code))
            f.write(struct.pack("<Q", off))

        # Alignment padding before tensor data.
        f.write(b"\x00" * padding)

        # Tensor data.
        for name, t in tensors:
            raw = _tensor_bytes(t)
            f.write(raw)
            pad = (_ALIGNMENT - len(raw) % _ALIGNMENT) % _ALIGNMENT
            if pad:
                f.write(b"\x00" * pad)

    return {
        "tensors_written":  len(tensors),
        "skipped_keys":     len(skipped),
        "skipped_examples": skipped[:5],
        "output_path":      gguf_path,
        "output_size_mb":   os.path.getsize(gguf_path) / 1e6,
        "base_arch":        base_arch,
        "alpha":            alpha,
    }


def main(argv=None):
    p = argparse.ArgumentParser(
        description="Convert a PyTorch LoRA .pt adapter to GGUF for "
                    "llama.cpp inference.")
    p.add_argument("--pt",    required=True, help="Input .pt LoRA path")
    p.add_argument("--gguf",  required=True, help="Output .gguf path")
    p.add_argument("--arch",  default="qwen2",
                   help="Base model arch (llama/qwen2/mistral/phi/...)")
    p.add_argument("--alpha", type=float, default=16.0,
                   help="LoRA alpha used at training time")
    p.add_argument("--dtype", choices=["f32", "f16", "bf16"], default=None,
                   help="Force-cast tensors to this dtype")
    args = p.parse_args(argv)

    stats = export_lora_to_gguf(args.pt, args.gguf,
                               base_arch=args.arch, alpha=args.alpha,
                               force_dtype=args.dtype)
    print(f"Wrote {stats['tensors_written']} tensors → "
          f"{stats['output_path']} ({stats['output_size_mb']:.1f} MB)")
    if stats["skipped_keys"]:
        print(f"Skipped {stats['skipped_keys']} non-LoRA keys "
              f"(first 5: {stats['skipped_examples']})")


if __name__ == "__main__":
    main()
